Here are the public test cases for feature7_2_query_job_requests:
{
  "description": "Creating a query job produces a job configuration with standard SQL, parameter mode, serialized parameters, dry-run settings, labels, timeout, job id or prefix, destination tables, and location where supplied.",
  "cases": [
    {
      "input": {
        "operation": "query_job_request",
        "options": {
          "query": "SELECT @name AS name",
          "params": {
            "name": "Ada"
          },
          "types": {
            "name": "STRING"
          },
          "dryRun": true,
          "labels": {
            "purpose": "test"
          }
        }
      },
      "expected_output": "{
  "configuration": {
    "query": {
      "useLegacySql": false,
      "query": "SELECT @name AS name",
      "types": {
        "name": "STRING"
      },
      "parameterMode": "named",
      "queryParameters": [
        {
          "parameterType": {
            "type": "STRING"
          },
          "parameterValue": {
            "value": "Ada"
          },
          "name": "name"
        }
      ]
    },
    "dryRun": true,
    "labels": {
      "purpose": "test"
    }
  }
}
"
    },
    {
      "input": {
        "operation": "query_job_request",
        "clientLocation": "EU",
        "options": {
          "query": "SELECT ? AS value",
          "params": [
            1
          ],
          "types": [
            "INT64"
          ],
          "jobPrefix": "pre-",
          "jobTimeoutMs": 1000
        }
      },
      "expected_output": "{
  "configuration": {
    "query": {
      "useLegacySql": false,
      "query": "SELECT ? AS value",
      "types": [
        "INT64"
      ],
      "parameterMode": "positional",
      "queryParameters": [
        {
          "parameterType": {
            "type": "INT64"
          },
          "parameterValue": {
            "value": 1
          }
        }
      ]
    },
    "jobTimeoutMs": 1000
  },
  "jobPrefix": "pre-"
}
"
    }
  ]
}

